+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {
+  end: number,
+  image: boolean,
+  label: string,
+  target: string,
+};
+
+function isEscaped(text: string, index: number): boolean {
+  let slashCount = 0;
+  for (let i = index - 1; i >= 0 && text[i] === '\\\'; i--) {
+    slashCount++;
+  }
+  return slashCount % 2 === 1;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const hashIndex = target.indexOf('#');
+  if (hashIndex === -1) {
+    return target;
+  }
+
+  const page = target.substring(0, hashIndex);
+  const heading = target.substring(hashIndex + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function convertWikiLinks(text: string, convertLinks: boolean, convertImages: boolean): string {
+  return text.replace(/(!)?\\[\\[([^\\]\
]+)\\]\\]/g, (match: string, embedIndicator: string, contents: string, offset: number) => {
+    if (isEscaped(text, offset)) {
+      return match;
+    }
+
+    const image = embedIndicator === '!';
+    if ((image && !convertImages) || (!image && !convertLinks)) {
+      return match;
+    }
+
+    const separatorIndex = contents.indexOf('|');
+    const target = separatorIndex === -1 ? contents : contents.substring(0, separatorIndex);
+    const display = separatorIndex === -1 ? undefined : contents.substring(separatorIndex + 1);
+    if (!target) {
+      return match;
+    }
+
+    if (image) {
+      const alt = display === undefined || /^\\d+(?:x\\d+)?$/.test(display) ? target : display;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | undefined {
+  const image = text[start] === '!';
+  const labelStart = start + (image ? 2 : 1);
+  let depth = 1;
+  let index = labelStart;
+
+  for (; index < text.length; index++) {
+    if (text[index] === '\
') {
+      return undefined;
+    }
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      break;
+    }
+  }
+
+  if (depth !== 0 || text[index + 1] !== '(') {
+    return undefined;
+  }
+
+  const label = unescapeMarkdown(text.substring(labelStart, index));
+  index += 2;
+  let target: string;
+
+  if (text[index] === '<') {
+    index++;
+    const targetStart = index;
+    for (; index < text.length && (text[index] !== '>' || isEscaped(text, index)); index++) {
+      if (text[index] === '\
') {
+        return undefined;
+      }
+    }
+    if (text[index] !== '>') {
+      return undefined;
+    }
+    target = unescapeMarkdown(text.substring(targetStart, index));
+    index++;
+    while (text[index] === ' ' || text[index] === '\	') {
+      index++;
+    }
+  } else {
+    const targetStart = index;
+    let parentheses = 0;
+    for (; index < text.length; index++) {
+      const character = text[index];
+      if (character === '\
' || character === ' ' || character === '\	') {
+        return undefined;
+      }
+      if (character === '\\\') {
+        index++;
+        continue;
+      }
+      if (character === '(') {
+        parentheses++;
+      } else if (character === ')') {
+        if (parentheses === 0) {
+          break;
+        }
+        parentheses--;
+      }
+    }
+    if (text[index] !== ')' || parentheses !== 0) {
+      return undefined;
+    }
+    target = unescapeMarkdown(text.substring(targetStart, index));
+  }
+
+  if (text[index] !== ')' || target.includes('://')) {
+    return undefined;
+  }
+
+  return {end: index + 1, image, label, target};
+}
+
+function convertMarkdownLinks(text: string, convertLinks: boolean, convertImages: boolean): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const startsImage = text[index] === '!' && text[index + 1] === '[';
+    const startsLink = text[index] === '[' && text[index - 1] !== '!';
+    if ((!startsImage && !startsLink) || isEscaped(text, index)) {
+      result += text[index++];
+      continue;
+    }
+
+    const parsed = parseMarkdownLink(text, index);
+    if (!parsed || (parsed.image ? !convertImages : !convertLinks)) {
+      result += text[index++];
+      continue;
+    }
+
+    if (parsed.image) {
+      const display = parsed.label === '' || parsed.label === parsed.target ? '' : `|${parsed.label}`;
+      result += `![[${parsed.target}${display}]]`;
+    } else {
+      const display = parsed.label === parsed.target || parsed.label === defaultHeadingDisplay(parsed.target) ? '' : `|${parsed.label}`;
+      result += `[[${parsed.target}${display}]]`;
+    }
+    index = parsed.end;
+  }
+
+  return result;
+}
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.yaml, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      return convertWikiLinks(text, options.linkStyle === 'markdown', options.imageStyle === 'markdown');
+    }
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      return convertMarkdownLinks(text, options.linkStyle === 'wiki', options.imageStyle === 'wiki');
+    }
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: '[[Page#Heading]] and ![[image.png|300x200]]',
+        after: '[Page > Heading](Page#Heading) and ![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
